select #{item.id}, #{item.tableInfoId}, #{item.fieldId, jdbcType = VARCHAR}, #{item.columnName}, #{item.fieldChineeName, jdbcType = VARCHAR}, #{item.fieldType, jdbcType = INTEGER}, #{item.fieldLen, jdbcType = INTEGER}, #{item.defaultValue, jdbcType = VARCHAR}, #{item.tableIndex, jdbcType = INTEGER}, #{item.indexType, jdbcType = INTEGER}, #{item.needValue, jdbcType = INTEGER}, #{item.recno, jdbcType = INTEGER}, #{item.partitionRecno, jdbcType = INTEGER}, #{item.clustRecno, jdbcType = INTEGER}, #{item.columnFieldType, jdbcType = INTEGER}, #{item.columnFieldLen, jdbcType = INTEGER} from dual
)
